import React, { useState } from 'react';
import { AppState, Post, SiteConfig } from '../types';
import { Button, Card, Input, TextArea } from './ui';
import { gemini } from '../services/geminiService';

interface AdminDashboardProps {
  state: AppState;
  onUpdateConfig: (config: SiteConfig) => void;
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ state, onUpdateConfig, onAddPost, onDeletePost }) => {
  const [activeTab, setActiveTab] = useState<'posts' | 'settings'>('posts');
  const [newPost, setNewPost] = useState<Partial<Post>>({ title: '', excerpt: '', content: '', category: 'Insights' });
  const [isAiLoading, setIsAiLoading] = useState(false);

  const handleAiGenerate = async () => {
    if (!newPost.title) return alert("Enter a title first");
    setIsAiLoading(true);
    const draft = await gemini.generateDraft(newPost.title);
    if (draft) {
      setNewPost(prev => ({ ...prev, ...draft }));
    }
    setIsAiLoading(false);
  };

  const handlePostSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newPost.title && newPost.content) {
      const post: Post = {
        id: Date.now().toString(),
        title: newPost.title,
        excerpt: newPost.excerpt || '',
        content: newPost.content,
        date: new Date().toISOString().split('T')[0],
        imageUrl: `https://picsum.photos/seed/${Date.now()}/800/450`,
        category: newPost.category || 'General'
      };
      onAddPost(post);
      setNewPost({ title: '', excerpt: '', content: '', category: 'Insights' });
    }
  };

  return (
    <div className="fixed inset-0 bg-black z-50 overflow-y-auto pt-20 pb-10">
      <div className="max-w-4xl mx-auto px-4">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-3xl font-bold font-brand text-blue-500">Admin Panel</h2>
          <div className="flex gap-2 bg-zinc-900 p-1 rounded-full border border-zinc-800">
            <button 
              onClick={() => setActiveTab('posts')}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${activeTab === 'posts' ? 'bg-blue-600 text-white' : 'text-gray-400 hover:text-white'}`}
            >
              Manage Posts
            </button>
            <button 
              onClick={() => setActiveTab('settings')}
              className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${activeTab === 'settings' ? 'bg-blue-600 text-white' : 'text-gray-400 hover:text-white'}`}
            >
              Site Settings
            </button>
          </div>
        </div>

        {activeTab === 'posts' ? (
          <div className="space-y-8">
            <Card className="p-6">
              <h3 className="text-xl font-semibold mb-4 text-white">Create New Post</h3>
              <form onSubmit={handlePostSubmit} className="space-y-4">
                <div className="flex gap-2">
                  <Input 
                    placeholder="Post Title" 
                    value={newPost.title} 
                    onChange={(e) => setNewPost({...newPost, title: e.target.value})} 
                  />
                  <Button variant="outline" onClick={handleAiGenerate}>
                    {isAiLoading ? "Thinking..." : "AI Draft ✨"}
                  </Button>
                </div>
                <Input 
                  placeholder="Category" 
                  value={newPost.category} 
                  onChange={(e) => setNewPost({...newPost, category: e.target.value})} 
                />
                <TextArea 
                  placeholder="Short Excerpt" 
                  value={newPost.excerpt} 
                  onChange={(e) => setNewPost({...newPost, excerpt: e.target.value})} 
                />
                <TextArea 
                  placeholder="Main Content" 
                  value={newPost.content} 
                  onChange={(e) => setNewPost({...newPost, content: e.target.value})} 
                  className="min-h-[200px]"
                />
                <Button type="submit" className="w-full">Publish Post</Button>
              </form>
            </Card>

            <div className="grid gap-4">
              <h3 className="text-xl font-semibold text-white">Current Posts</h3>
              {state.posts.map(post => (
                <Card key={post.id} className="p-4 flex justify-between items-center">
                  <div>
                    <h4 className="font-semibold text-white">{post.title}</h4>
                    <p className="text-sm text-gray-400">{post.date} • {post.category}</p>
                  </div>
                  <Button variant="ghost" className="text-red-500 hover:bg-red-500/10" onClick={() => onDeletePost(post.id)}>
                    Delete
                  </Button>
                </Card>
              ))}
            </div>
          </div>
        ) : (
          <Card className="p-6 space-y-6">
            <h3 className="text-xl font-semibold text-white">General Customization</h3>
            <div className="space-y-4">
              <div>
                <label className="text-sm text-gray-400 mb-1 block">Site Name</label>
                <Input value={state.config.siteName} onChange={(e) => onUpdateConfig({...state.config, siteName: e.target.value})} />
              </div>
              <div>
                <label className="text-sm text-gray-400 mb-1 block">Hero Heading</label>
                <TextArea value={state.config.heroHeading} onChange={(e) => onUpdateConfig({...state.config, heroHeading: e.target.value})} />
              </div>
              <div>
                <label className="text-sm text-gray-400 mb-1 block">Hero Subheading</label>
                <TextArea value={state.config.heroSubheading} onChange={(e) => onUpdateConfig({...state.config, heroSubheading: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm text-gray-400 mb-1 block">SEO Keywords</label>
                  <Input value={state.config.seoKeywords} onChange={(e) => onUpdateConfig({...state.config, seoKeywords: e.target.value})} />
                </div>
                <div>
                  <label className="text-sm text-gray-400 mb-1 block">Primary Accent Color</label>
                  <Input type="color" value={state.config.primaryColor} onChange={(e) => onUpdateConfig({...state.config, primaryColor: e.target.value})} />
                </div>
              </div>
            </div>
          </Card>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

