export default function App() {
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('ai_economics_state');
    return saved ? JSON.parse(saved) : { config: DEFAULT_CONFIG, posts: INITIAL_POSTS };
  });

  useEffect(() => {
    localStorage.setItem('ai_economics_state', JSON.stringify(state));
  }, [state]);

  const updateConfig = (newConfig: SiteConfig) => setState(prev => ({ ...prev, config: newConfig }));

  const addPost = (post: Post) => setState(prev => ({ ...prev, posts: [post, ...prev.posts] }));

  const deletePost = (id: string) => setState(prev => ({ ...prev, posts: prev.posts.filter(p => p.id !== id) }));

  return (
    <Router>
      <div className="min-h-screen selection:bg-blue-500/30">
        <Navbar 
          siteName={state.config.siteName} 
          onAdminToggle={() => setIsAdminOpen(!isAdminOpen)} 
          isAdminOpen={isAdminOpen}
        />

        {isAdminOpen && (
          <AdminDashboard 
            state={state} 
            onUpdateConfig={updateConfig} 
            onAddPost={addPost} 
            onDeletePost={deletePost}
          />
        )}

        <Routes>
          <Route path="/" element={
            <main>
              <Hero config={state.config} />
              <LatestPosts posts={state.posts} />
              <Footer siteName={state.config.siteName} />
            </main>
          } />
          <Route path="/insights" element={
            <div className="pt-32 px-6 max-w-7xl mx-auto min-h-screen">
               <h1 className="text-4xl font-brand font-bold mb-12">All Insights</h1>
               <LatestPosts posts={state.posts} />
            </div>
          } />
        </Routes>
      </div>
    </Router>
  );
}

