    const saved = localStorage.getItem('ai_economics_state');
    return saved ? JSON.parse(saved) : { config: DEFAULT_CONFIG, posts: INITIAL_POSTS };
  });

  useEffect(() => {
    localStorage.setItem('ai_economics_state', JSON.stringify(state));
  }, [state]);

  const updateConfig = (newConfig: SiteConfig) => setState(prev => ({ ...prev, config: newConfig }));
  const addPost = (post: Post) => setState(prev => ({ ...prev, posts: [post, ...prev.posts] }));
  const deletePost = (id: string) => setState(prev => ({ ...prev, posts: prev.posts.filter(p => p.id !== id) }));

  return (
    <Router>
      <div className="min-h-screen bg-[#020205] selection:bg-indigo-500/30">
        <Navbar 
          siteName={state.config.siteName} 
          onAdminToggle={() => setIsAdminOpen(!isAdminOpen)} 
