          <AdminDashboard 
            state={state} 
            onUpdateConfig={updateConfig} 
            onAddPost={addPost} 
            onDeletePost={deletePost}
          />
        )}

        <Routes>
          <Route path="/" element={
            <main>
              <Hero config={state.config} />
