import React, { useState, useRef } from 'react';
import { AppState, Profile, SiteConfig } from '../types.ts';
import { Button, Card, Input, TextArea } from './ui.tsx';
import { gemini } from '../services/geminiService.ts';

interface AdminDashboardProps {
  state: AppState;
  onUpdateConfig: (config: SiteConfig) => void;
  onUpdateProfile: (profile: Profile) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ state, onUpdateConfig, onUpdateProfile }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'settings'>('profile');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAiEnhanceBio = async () => {
    setIsAiLoading(true);
    const result = await gemini.generateDraft(`Enhance this bio: ${state.profile.bio}`);
    if (result) onUpdateProfile({ ...state.profile, bio: result.content });
    setIsAiLoading(false);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const img = new Image();
        img.onload = () => {
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;
          if (width > MAX_WIDTH) {
            height = Math.round((height * MAX_WIDTH) / width);
            width = MAX_WIDTH;
          }
          const canvas = document.createElement('canvas');
          canvas.width = width; canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.drawImage(img, 0, 0, width, height);
            const compressedBase64 = canvas.toDataURL('image/jpeg', 0.6); // 더 높은 압축률
            onUpdateProfile({ ...state.profile, imageUrl: compressedBase64 });
          }
        };
        img.src = e.target?.result as string;
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/95 z-50 overflow-y-auto pt-20 pb-10">
      <div className="max-w-4xl mx-auto px-4">
        <div className="flex justify-between items-center mb-8 border-b border-white/10 pb-4">
          <h2 className="text-2xl font-bold text-indigo-500 uppercase tracking-tighter">CMS Control</h2>
          <div className="flex gap-4">
            <button onClick={() => setActiveTab('profile')} className={`text-xs font-bold ${activeTab === 'profile' ? 'text-white' : 'text-gray-500'}`}>Profile</button>
            <button onClick={() => setActiveTab('settings')} className={`text-xs font-bold ${activeTab === 'settings' ? 'text-white' : 'text-gray-500'}`}>Settings</button>
          </div>
        </div>

        {activeTab === 'profile' ? (
          <Card className="p-8 space-y-6">
            <div className="flex gap-6">
              <div className="w-24 h-24 bg-zinc-800 rounded-lg overflow-hidden border border-white/10">
                <img src={state.profile.imageUrl} className="w-full h-full object-cover" />
              </div>
              <Button onClick={() => fileInputRef.current?.click()} variant="outline">Upload New Photo</Button>
              <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
            </div>
            <div className="space-y-4">
              <Input placeholder="Name" value={state.profile.name} onChange={(e) => onUpdateProfile({...state.profile, name: e.target.value})} />
              <Input placeholder="Title" value={state.profile.title} onChange={(e) => onUpdateProfile({...state.profile, title: e.target.value})} />
              <TextArea placeholder="Bio" value={state.profile.bio} onChange={(e) => onUpdateProfile({...state.profile, bio: e.target.value})} />
              <Button onClick={handleAiEnhanceBio} disabled={isAiLoading} className="w-full">{isAiLoading ? "Processing..." : "AI Enhance Bio"}</Button>
            </div>
          </Card>
        ) : (
          <Card className="p-8 space-y-4">
            <Input label="Site Name" value={state.config.siteName} onChange={(e) => onUpdateConfig({...state.config, siteName: e.target.value})} />
            <TextArea label="Hero Subheading" value={state.config.heroSubheading} onChange={(e) => onUpdateConfig({...state.config, heroSubheading: e.target.value})} />
          </Card>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

