export default function App() {
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [state, setState] = useState<AppState>(() => {
    try {
      const saved = localStorage.getItem('ai_economics_v6_restored');
      if (saved) return JSON.parse(saved);
    } catch (e) { console.error(e); }
    return { config: DEFAULT_CONFIG, profile: INITIAL_PROFILE };
  });

  useEffect(() => {
    localStorage.setItem('ai_economics_v6_restored', JSON.stringify(state));
  }, [state]);

  const updateConfig = (newConfig: SiteConfig) => setState(prev => ({ ...prev, config: newConfig }));
  const updateProfile = (newProfile: Profile) => setState(prev => ({ ...prev, profile: newProfile }));

  return (
    <Router>
      <ScrollToTop />
      <div className="min-h-screen bg-[#020205] selection:bg-indigo-500/30 text-white relative">
        <BackgroundLayer />
        <Navbar siteName={state.config?.siteName} onAdminToggle={() => setIsAdminOpen(!isAdminOpen)} />
        {isAdminOpen && <AdminDashboard state={state} onUpdateConfig={updateConfig} onUpdateProfile={updateProfile} />}
        <Routes>
          <Route path="/" element={<main><Hero config={state.config} /></main>} />
          <Route path="/profile" element={<ProfileView profile={state.profile} />} />
          <Route path="/contact" element={<ContactView />} />
        </Routes>
      </div>
    </Router>
  );
}

import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private getClient() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async suggestSEO(content: string) {
    try {
      const ai = this.getClient();
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Given the following content, suggest 5 highly relevant SEO keywords and a 160-character meta description. Content: ${content}`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              metaDescription: { type: Type.STRING }
            },
            required: ['keywords', 'metaDescription']
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (error) {
      console.error("Gemini Error:", error);
      return null;
    }
  }

  async generateDraft(topic: string) {
    try {
      const ai = this.getClient();
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a short professional economic consulting bio or summary about: ${topic}. Format as a clear narrative.`,
        config: {
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              excerpt: { type: Type.STRING },
              content: { type: Type.STRING }
            },
            required: ['title', 'excerpt', 'content']
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (error) {
      console.error("Gemini Error:", error);
      return null;
    }
  }
}

